function getNewPath(oldPath: string): string {
  return SLUG_OVERRIDES[oldPath] || oldPath;
}

async function scanBrainFiles(): Promise<MigrationEntry[]> {
  const entries: MigrationEntry[] = [];

  async function scanDir(dir: string): Promise<void> {
    if (!existsSync(dir)) return;
    const items = await readdir(dir, { withFileTypes: true });
    for (const item of items) {
      const fullPath = join(dir, item.name);
      if (item.isDirectory()) {
        if (item.name.startsWith("_") || item.name === "templates") continue;
        await scanDir(fullPath);
      } else if (item.isFile() && item.name.endsWith(".md")) {
        const relPath = relative(BRAIN_DIR, fullPath);

        // Skip internal files
        if (SKIP_FILES.has(item.name)) continue;

        const raw = readFileSync(fullPath, "utf-8");
        const parsed = matter(raw);
        const fm = (parsed.data || {}) as Record<string, unknown>;
        const type = (fm.type as string) || deduceTypeFromPath(relPath);
        const content = parsed.content;
        const rawTitle = (fm.title as string) || extractTitle(content) || nameFromFilename(item.name);
        const title = cleanHumanTitle(rawTitle);

        const newRelPath = getNewPath(relPath);
        const domain = classifyDomain(relPath, type);

        entries.push({
          oldRelativePath: relPath,
          newRelativePath: newRelPath,
          type,
          title,
          proposedDomain: domain,
          changed: relPath !== newRelPath,
        });
      }
    }
  }

  await scanDir(BRAIN_DIR);
  return entries;
}

function deduceTypeFromPath(relPath: string): string {
  const dir = dirname(relPath);
  if (dir === "person") return "person";
  if (dir === "patterns") return "patterns";
  if (dir === "self") return "self";
  if (dir === "sessions") return "sessions";
  if (dir === "daily") return "daily";
  if (dir === "projects" || dir.startsWith("projects/")) return "projects";
  return "unknown";
}

function nameFromFilename(filename: string): string {
  return filename.replace(/\.md$/, "").replace(/[-_]/g, " ");
}

// ─── Preview ──────────────────────────────────────────────────────────

function formatPreview(entries: MigrationEntry[]): string {
  const lines: string[] = [];
  let renamed = 0;
  let codingCount = 0;

  const byType = new Map<string, MigrationEntry[]>();
  for (const e of entries) {
    const key = e.type;
    if (!byType.has(key)) byType.set(key, []);
    byType.get(key)!.push(e);
  }

  for (const [type, group] of byType) {
    lines.push(`\n## ${type} (${group.length})`);
    for (const e of group) {
      const flag = e.changed ? " 🔄" : "  ✓";
      if (e.changed) renamed++;
      const tag = e.proposedDomain === "coding" ? " [CODING]" : e.proposedDomain === "both" ? " [BOTH]" : "";
      if (e.proposedDomain === "coding") codingCount++;
      lines.push(`  ${flag} ${e.oldRelativePath}`);
      if (e.changed) {
        lines.push(`      → ${e.newRelativePath}${tag}`);
      }
      lines.push(`      Title: ${e.title}`);
      lines.push("");
    }
  }

  const bothCount = entries.filter(e => e.proposedDomain === "both").length;
  const personalCount = entries.filter(e => e.proposedDomain === "personal").length;
  const previewLines = [
    `Summary: ${entries.length} files`,
    `  Renamed: ${renamed}`,
    `  Unchanged: ${entries.length - renamed}`,
    `  Coding: ${codingCount}  |  Both: ${bothCount}  |  Personal: ${personalCount}`,
    "",
    lines.join("\n"),
  ];

  return previewLines.join("\n");
}

// ─── Apply ────────────────────────────────────────────────────────────

function applyMigration(entries: MigrationEntry[]): void {
  let renamed = 0;
  let updated = 0;

  for (const e of entries) {
    const oldPath = join(BRAIN_DIR, e.oldRelativePath);
    const newPath = join(BRAIN_DIR, e.newRelativePath);

    if (!existsSync(oldPath)) {
      console.error(`  [SKIP] Not found: ${e.oldRelativePath}`);
      continue;
    }

    const raw = readFileSync(oldPath, "utf-8");
    const parsed = matter(raw);
    const fm = (parsed.data || {}) as Record<string, unknown>;

    // Always set title
    fm.title = e.title;

    // Set domain if not present
    if (!fm.domain) {
      fm.domain = e.proposedDomain;
    }

    const newRaw = matter.stringify(parsed.content, fm);

    if (e.changed) {
      const targetDir = dirname(newPath);
      if (!existsSync(targetDir)) mkdirSync(targetDir, { recursive: true });

      writeFileSync(newPath, newRaw, "utf-8");
      renameSync(oldPath, newPath);
      renamed++;
      console.log(`  [RENAME] ${e.oldRelativePath} → ${e.newRelativePath}`);
    } else {
      writeFileSync(oldPath, newRaw, "utf-8");
      updated++;
      console.log(`  [UPDATE] ${e.oldRelativePath}`);
    }
  }

  console.log(`\nDone: ${renamed} renamed, ${updated} frontmatter-updated`);
}

// ─── Main ─────────────────────────────────────────────────────────────

async function main(): Promise<void> {
  const args = process.argv.slice(2);
  const apply = args.includes("--apply");

  console.log("Scanning brain files...\n");

  const entries = await scanBrainFiles();

  console.log(formatPreview(entries));

  if (!apply) {
    console.log("\n---");
    console.log("This is a preview. Run with --apply to execute.");
    console.log("Set any missing overrides in SLUG_OVERRIDES map first.");
    process.exit(0);
  }

  console.log("\nApplying migration...\n");
  applyMigration(entries);
}

main().catch(err => {
  console.error("Migration failed:", err);
  process.exit(1);
});

#!/usr/bin/env tsx
// recall.ts — Search the third-brain
// Usage: tsx scripts/recall.ts "what does Nik prefer for scripting"
//        tsx scripts/recall.ts --type person --tag nik
//        tsx scripts/recall.ts --limit 5 "job search"

import { join } from "node:path";
import { parseArgs } from "node:util";
import { BrainStore } from "./store.js";
import type { SearchResult } from "./types.js";

const ROOT_DIR = join(import.meta.dirname, "..");
const DB_PATH = join(ROOT_DIR, "index", "memory.db");

interface RecallArgs {
  query: string;
  type?: string;
  tag?: string;
  domain?: string;
  limit: number;
}

function parseCliArgs(): RecallArgs {
  const { values, positionals } = parseArgs({
    args: process.argv.slice(2),
    options: {
      type: { type: "string" },
      tag: { type: "string" },
      domain: { type: "string" },
      limit: { type: "string", default: "10" },
    },
    allowPositionals: true,
  });

  return {
    query: positionals.join(" ") || "",
    type: values.type as string | undefined,
    tag: values.tag as string | undefined,
    domain: values.domain as string | undefined,
    limit: parseInt(values.limit as string, 10) || 10,
  };
}

async function recall(args: RecallArgs): Promise<SearchResult[]> {
  const store = new BrainStore(DB_PATH);

  // Determine effective domain filter
  // Special values: coding+both, coding+personal
  const domain = args.domain;

  let results: SearchResult[];

  if (args.tag) {
    // searchByTag doesn't support domain — post-filter
    results = store.searchByTag(args.tag, args.limit * 2);
    if (domain) {
      results = results.filter(r => r.tags.includes(domain));
    }
    results = results.slice(0, args.limit);
  } else if (args.type && args.query) {
    results = store.searchByType(args.query, args.type, args.limit, domain);
  } else if (args.type) {
    // List all of a type with optional domain filter
    const files = domain ? store.listFiles(args.type, domain) : store.listFiles(args.type);
    results = files.slice(0, args.limit).map(f => ({
      file: f.path,
      type: f.type,
      tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
      title: f.title,
      excerpt: f.content.slice(0, 200),
      score: 1,
    }));
  } else if (args.query) {
    results = store.search(args.query, args.limit, domain);
  } else {
    // No filter — list recent with optional domain filter
    const files = domain ? store.listFiles(undefined, domain) : store.listFiles();
    results = files.slice(0, args.limit).map(f => ({
      file: f.path,
      type: f.type,
      tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
      title: f.title,
      excerpt: f.content.slice(0, 200),
      score: 1,
    }));
  }

  store.close();
  return results;
}

function formatResults(results: SearchResult[], showDomain?: boolean): string {
  if (results.length === 0) return "No memories found.";

  const lines: string[] = [];
  for (const r of results) {
    lines.push(`[${r.type}] ${r.title} (${r.file})`);
    lines.push(`  ${r.excerpt.replace(/\n/g, " ").slice(0, 150)}`);
    if (r.tags.length > 0) lines.push(`  tags: ${r.tags.join(", ")}`);
    if (showDomain && (r as any).domain) lines.push(`  domain: ${(r as any).domain}`);
    lines.push("");
  }
  return lines.join("\n");
}

// Allow programmatic use
export async function recallMemory(
  query: string,
  options?: { type?: string; tag?: string; domain?: string; limit?: number }
): Promise<SearchResult[]> {
  return recall({
    query,
    type: options?.type,
    tag: options?.tag,
    domain: options?.domain,
    limit: options?.limit || 10,
  });
}

// CLI entry point
if (import.meta.url === `file://${process.argv[1]}` || process.argv[1]?.endsWith("/recall.ts")) {
  const args = parseCliArgs();
  recall(args).then(results => {
    console.log(formatResults(results));
  }).catch(err => {
    console.error("recall failed:", err);
    process.exit(1);
  });
}

#!/usr/bin/env tsx
// remember.ts — Write a memory to the brain (markdown + index)
// Usage: tsx scripts/remember.ts --type person --file people/nik.md --section "Key Facts" --content "Prefers Deno over Node" --tags "nik,coding"
//        tsx scripts/remember.ts --type daily --content "Nik seemed energized today" --tags "mood"
//        tsx scripts/remember.ts --type projects --project dots --org nikbrunner --content "Refactored project dir structure" --tags "maintenance"

import { join } from "node:path";
import { parseArgs } from "node:util";
import { BrainStore } from "./store.js";
import { appendToSection, dailyNotePath, today, tagsToString, extractTitle } from "./markdown.js";
import { commitFile } from "./git.js";
import type { BrainFileType } from "./types.js";

const ROOT_DIR = join(import.meta.dirname, "..");
const DB_PATH = join(ROOT_DIR, "index", "memory.db");

interface RememberArgs {
  type: BrainFileType;
  file?: string;
  section?: string;
  content: string;
  tags: string;
  project?: string;
  org?: string;
  commit?: boolean;
}

function parseCliArgs(): RememberArgs {
  const { values } = parseArgs({
    args: process.argv.slice(2),
    options: {
      type: { type: "string", default: "daily" },
      file: { type: "string" },
      section: { type: "string", default: "Key Facts" },
      content: { type: "string" },
      tags: { type: "string", default: "" },
      project: { type: "string" },
      org: { type: "string", default: "nikbrunner" },
      commit: { type: "boolean", default: true },
    },
    allowPositionals: true,
  });

  // Support positional content argument
  const content = values.content || (values as Record<string, unknown>)._[0] as string;
  if (!content) {
    console.error("Error: --content required (or pass as positional argument)");
    process.exit(1);
  }

  return {
    type: (values.type || "daily") as BrainFileType,
    file: values.file as string | undefined,
    section: (values.section || "Key Facts") as string,
    content,
    tags: (values.tags || "") as string,
    project: values.project as string | undefined,
    org: (values.org || "nikbrunner") as string,
    commit: values.commit as boolean | undefined,
  };
}

async function remember(args: RememberArgs): Promise<void> {
  const store = new BrainStore(DB_PATH);

  // Determine the target file
  let filePath: string;
  if (args.file) {
    filePath = args.file;
  } else if (args.type === "daily") {
    filePath = dailyNotePath(today());
  } else if (args.type === "projects" && args.project) {
    filePath = `projects/${args.org}/${args.project}/${today()}.md`;
  } else {
    const slug = args.content.slice(0, 40).toLowerCase().replace(/[^a-z0-9]+/g, "-");
    filePath = `${args.type}/${slug}.md`;
  }

  const tags = args.tags.split(",").map(t => t.trim()).filter(Boolean);

  // Write to markdown
  const updatedFile = appendToSection(
    filePath,
    args.section,
    args.content,
    {
      type: args.type,
      tags,
      updated: today(),
    }
  );

  // Update index
  const title = extractTitle(updatedFile.content);
  store.upsertFile({
    path: updatedFile.path,
    checksum: updatedFile.checksum,
    type: updatedFile.frontmatter.type || args.type,
    tags: tagsToString(updatedFile.frontmatter.tags || tags),
    title,
    content: updatedFile.content,
    updated: updatedFile.frontmatter.updated || today(),
    indexed_at: new Date().toISOString(),
  });

  console.log(`Remembered in ${updatedFile.path}: ${args.content}`);
  store.close();

  if (args.commit) {
    commitFile(ROOT_DIR, updatedFile.path, args.content);
  }
}

// Allow programmatic use
export async function rememberMemory(
  type: BrainFileType,
  content: string,
  options?: { file?: string; section?: string; tags?: string[]; project?: string; org?: string; commit?: boolean }
): Promise<string> {
  const filePath = options?.file
    || (type === "daily" ? dailyNotePath(today())
    : (type === "projects" && options?.project)
      ? `projects/${options.org || "nikbrunner"}/${options.project}/${today()}.md`
      : `${type}/${content.slice(0, 40).toLowerCase().replace(/[^a-z0-9]+/g, "-")}.md`);
  const section = options?.section || "Key Facts";
  const tags = options?.tags || [];

  const updatedFile = appendToSection(filePath, section, content, { type, tags, updated: today() });

  const store = new BrainStore(DB_PATH);
  store.upsertFile({
    path: updatedFile.path,
    checksum: updatedFile.checksum,
    type,
    tags: tagsToString(tags),
    title: extractTitle(updatedFile.content),
    content: updatedFile.content,
    updated: today(),
    indexed_at: new Date().toISOString(),
  });
  store.close();

  if (options?.commit !== false) {
    commitFile(ROOT_DIR, updatedFile.path, content);
  }

  return updatedFile.path;
}

// CLI entry point
if (import.meta.url === `file://${process.argv[1]}` || process.argv[1]?.endsWith("/remember.ts")) {
  const args = parseCliArgs();
  remember(args).catch(err => {
    console.error("remember failed:", err);
    process.exit(1);
  });
}

#!/usr/bin/env tsx
// session-start.ts — Inject brain context at session start
// Called from Claude Code SessionStart hook or pi session_start.
// Reads stdin JSON from hook, searches brain for relevant context,
// outputs context block to stdout (which becomes system prompt context).
//
// Usage: Called automatically by hook. No CLI arguments needed.

import { readFileSync, existsSync } from "node:fs";
import { join } from "node:path";
import matter from "gray-matter";
import { BrainStore } from "./store.js";

const ROOT_DIR = join(import.meta.dirname, "..");
const DB_PATH = join(ROOT_DIR, "index", "memory.db");
const BRAIN_DIR = join(ROOT_DIR, "brain");

const MAX_CONTEXT_CHARS = 4000;

type DomainMode = "coding" | "personal";

function readMode(): DomainMode {
  // Check brain/self/mode.md for a mode override
  const modePath = join(BRAIN_DIR, "self", "mode.md");
  if (existsSync(modePath)) {
    try {
      const raw = readFileSync(modePath, "utf-8");
      const parsed = matter(raw);
      const data = parsed.data as Record<string, unknown>;
      if (data.mode === "personal") return "personal";
    } catch {
      // Ignore parse errors
    }
  }
  // Default to coding mode
  return "coding";
}

interface SessionStartInput {
  session_id?: string;
  cwd?: string;
  hook_event_name?: string;
}

function readInput(): SessionStartInput {
  try {
    const stdin = readFileSync(0, "utf-8").trim();
    if (stdin) return JSON.parse(stdin);
  } catch {
    // no stdin
  }
  return {};
}

function getCwdPrompt(): string {
  // Try to extract a project name from cwd
  try {
    const input = readInput();
    if (input.cwd) {
      const parts = input.cwd.split("/").filter(Boolean);
      const skip = new Set(["Users", "home", "nbr", "repos", "nikbrunner", "workplace"]);
      const relevant = parts.filter(p => !skip.has(p));
      return relevant.join(" ");
    }
  } catch {
    // ignore
  }
  return "";
}

async function buildContext(mode: DomainMode): Promise<string> {
  const store = new BrainStore(DB_PATH);
  const sections: string[] = [];

  // Determine the effective domain filter
  // coding mode: show coding + both
  // personal mode: show personal + both (no filter)
  const domainFilter = mode === "coding" ? "coding+both" : undefined;

  // 1. Penny's self-model (always injected, regardless of mode)
  const selfFiles = store.searchByType("penny", "self", 1);
  if (selfFiles.length > 0) {
    sections.push(`## My Self-Model\n${selfFiles[0].excerpt}`);
  }

  // 2. People context (key facts about Nik — always injected, regardless of mode)
  const peopleFiles = store.searchByType("nik", "person", 2);
  if (peopleFiles.length > 0) {
    const facts = peopleFiles.map(f => f.excerpt).join("\n");
    sections.push(`## About Nik\n${facts.slice(0, 800)}`);
  }

  // 3. Project context (from cwd) — domain filtered
  const cwdPrompt = getCwdPrompt();
  if (cwdPrompt) {
    const projectResults = store.search(cwdPrompt, 3, domainFilter);
    if (projectResults.length > 0) {
      const projectContext = projectResults.map(r => `- [${r.type}] ${r.excerpt}`).join("\n");
      sections.push(`## Project Context\n${projectContext}`);
    }
  }

  // 4. Recent patterns — domain filtered via listFiles
  const patternFiles = store.listFiles("patterns", domainFilter);
  if (patternFiles.length > 0) {
    const patternContext = patternFiles.slice(0, 3).map(f =>
      `- ${f.title}: ${f.content.slice(0, 150)}`
    ).join("\n");
    sections.push(`## Patterns\n${patternContext}`);
  }

  // 5. Recent sessions
  const sessions = store.searchByType("sessions", "sessions", 3, domainFilter);
  if (sessions.length > 0) {
    const sessionContext = sessions.map(r => `- ${r.title}: ${r.excerpt.slice(0, 100)}`).join("\n");
    sections.push(`## Recent Sessions\n${sessionContext}`);
  }

  // 6. Important lessons (corrections to remember) — domain filtered via listFiles
  const correctionFiles = store.listFiles(undefined, domainFilter)
    .filter(f => f.tags.includes("correction"));
  if (correctionFiles.length > 0) {
    const correctionContext = correctionFiles.slice(0, 3).map(f =>
      `- ${f.content.slice(0, 150)}`
    ).join("\n");
    sections.push(`## Before Acting\n${correctionContext}`);
  }

  store.close();

  if (sections.length === 0) return "";

  const modeLabel = mode === "coding" ? "coding mode" : "personal mode";
  let text = `<penny_brain mode="${modeLabel}">\n${sections.join("\n\n")}\n\n## Reminder\n- Memory records can become stale. Verify before relying on them.\n- If memory conflicts with what you observe, trust observation.\n</penny_brain>`;

  if (text.length > MAX_CONTEXT_CHARS) {
    text = text.slice(0, MAX_CONTEXT_CHARS - 20) + "\n... (truncated)\n</penny_brain>";
  }

  return text;
}

async function main(): Promise<void> {
  const mode = readMode();
  const context = await buildContext(mode);
  if (context) {
    // Output in Claude Code hook format: JSON with additionalContext
    // Plain text also works for SessionStart (Claude injects stdout as context)
    // but JSON format is more explicit and reliable.
    const escaped = context.replace(/\\/g, "\\\\").replace(/"/g, '\\"').replace(/\n/g, "\\n");
    console.log(JSON.stringify({
      hookSpecificOutput: {
        hookEventName: "SessionStart",
        additionalContext: escaped,
      },
    }));
  }
}

main().catch(err => {
  console.error("session-start failed:", err);
  process.exit(1);
});

// SQLite store for the third-brain index
// Wraps Node's built-in node:sqlite — FTS5 search on markdown content

import { DatabaseSync } from "node:sqlite";
import { mkdirSync, existsSync } from "node:fs";
import { dirname } from "node:path";
import type { IndexedFile, SearchResult } from "./types.js";

export class BrainStore {
  private db: DatabaseSync;
  private hasFTS5 = false;

  constructor(dbPath: string) {
    const dir = dirname(dbPath);
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });

    this.db = new DatabaseSync(dbPath);
    this.db.exec("PRAGMA journal_mode = WAL");
    this.db.exec("PRAGMA busy_timeout = 5000");
    this.migrate();
  }

  private migrate(): void {
    this.db.exec(`
      CREATE TABLE IF NOT EXISTS files (
        path TEXT PRIMARY KEY,
        checksum TEXT NOT NULL,
        type TEXT NOT NULL,
        tags TEXT NOT NULL DEFAULT '',
        title TEXT NOT NULL DEFAULT '',
        content TEXT NOT NULL DEFAULT '',
        updated TEXT NOT NULL DEFAULT '',
        domain TEXT NOT NULL DEFAULT '',
        indexed_at TEXT NOT NULL DEFAULT (datetime('now'))
      );
    `);

    // Add domain column if missing (migration from older schema)
    try {
      this.db.exec("ALTER TABLE files ADD COLUMN domain TEXT NOT NULL DEFAULT ''");
    } catch {
      // Column already exists — safe to ignore
    }

    // Try FTS5 — fall back to substring if unavailable
    try {
      this.db.exec(`
        CREATE VIRTUAL TABLE IF NOT EXISTS files_fts USING fts5(
          path, title, content, tags, domain,
          content='files', content_rowid='rowid'
        );

        CREATE TRIGGER IF NOT EXISTS files_ai AFTER INSERT ON files BEGIN
          INSERT INTO files_fts(rowid, path, title, content, tags, domain)
          VALUES (new.rowid, new.path, new.title, new.content, new.tags, new.domain);
        END;
        CREATE TRIGGER IF NOT EXISTS files_ad AFTER DELETE ON files BEGIN
          INSERT INTO files_fts(files_fts, rowid, path, title, content, tags, domain)
          VALUES('delete', old.rowid, old.path, old.title, old.content, old.tags, old.domain);
        END;
        CREATE TRIGGER IF NOT EXISTS files_au AFTER UPDATE ON files BEGIN
          INSERT INTO files_fts(files_fts, rowid, path, title, content, tags, domain)
          VALUES('delete', old.rowid, old.path, old.title, old.content, old.tags, old.domain);
          INSERT INTO files_fts(rowid, path, title, content, tags, domain)
          VALUES (new.rowid, new.path, new.title, new.content, new.tags, new.domain);
        END;
      `);
      this.hasFTS5 = true;
    } catch {
      this.hasFTS5 = false;
    }
  }

  // ─── File operations ──────────────────────────────────────────────

  upsertFile(file: IndexedFile): void {
    this.db.prepare(`
      INSERT INTO files (path, checksum, type, tags, title, content, updated, domain, indexed_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, datetime('now'))
      ON CONFLICT(path) DO UPDATE SET
        checksum = excluded.checksum,
        type = excluded.type,
        tags = excluded.tags,
        title = excluded.title,
        content = excluded.content,
        updated = excluded.updated,
        domain = excluded.domain,
        indexed_at = datetime('now')
    `).run(
      file.path || "",
      file.checksum || "",
      file.type || "unknown",
      file.tags || "",
      file.title || "",
      file.content || "",
      file.updated || "",
      file.domain || ""
    );
  }

  getFile(path: string): IndexedFile | undefined {
    return this.db.prepare("SELECT * FROM files WHERE path = ?").get(path) as IndexedFile | undefined;
  }

  deleteFile(path: string): boolean {
    const result = this.db.prepare("DELETE FROM files WHERE path = ?").run(path);
    return result.changes > 0;
  }

  listFiles(type?: string, domain?: string): IndexedFile[] {
    let sql = "SELECT * FROM files";
    const conditions: string[] = [];
    const params: unknown[] = [];

    if (type) {
      conditions.push("type = ?");
      params.push(type);
    }
    if (domain) {
      if (domain === "both") {
        conditions.push("(domain = ? OR domain = '')");
        params.push(domain);
      } else if (domain === "coding+personal") {
        // Special: show coding and personal but not both
        conditions.push("domain IN (?, ?)");
        params.push("coding", "personal");
      } else {
        conditions.push("domain = ?");
        params.push(domain);
      }
    }

    if (conditions.length > 0) {
      sql += " WHERE " + conditions.join(" AND ");
    }
    sql += " ORDER BY updated DESC";

    return this.db.prepare(sql).all(...params) as IndexedFile[];
  }

  // ─── Search ────────────────────────────────────────────────────────

  search(query: string, limit = 10, domain?: string): SearchResult[] {
    const terms = query.trim().split(/\s+/).filter(Boolean);
    if (terms.length === 0) return [];

    if (this.hasFTS5) {
      return this._searchFTS(query, limit, undefined, domain);
    }
    return this._searchFallback(query, limit, undefined, domain);
  }

  searchByType(query: string, type: string, limit = 10, domain?: string): SearchResult[] {
    const terms = query.trim().split(/\s+/).filter(Boolean);
    if (terms.length === 0) {
      const files = domain ? this.listFiles(type, domain) : this.listFiles(type);
      return files.map(f => ({
        file: f.path,
        type: f.type,
        tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
        title: f.title,
        excerpt: f.content.slice(0, 200),
        score: 1,
      }));
    }

    if (this.hasFTS5) {
      return this._searchFTS(query, limit, type, domain);
    }
    return this._searchFallback(query, limit, type, domain);
  }

  searchByDomain(domain: string, limit = 50): SearchResult[] {
    const files = this.listFiles(undefined, domain);
    return files.slice(0, limit).map(f => ({
      file: f.path,
      type: f.type,
      tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
      title: f.title,
      excerpt: f.content.slice(0, 200),
      score: 1,
    }));
  }

  searchByTag(tag: string, limit = 50): SearchResult[] {
    const files = this.db.prepare(
      "SELECT * FROM files WHERE tags LIKE ? ORDER BY updated DESC LIMIT ?"
    ).all(`%${tag}%`, limit) as IndexedFile[];

    return files.map(f => ({
      file: f.path,
      type: f.type,
      tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
      title: f.title,
      excerpt: f.content.slice(0, 200),
      score: 1,
    }));
  }

  private _searchFTS(query: string, limit: number, type?: string, domain?: string): SearchResult[] {
    const terms = query.trim().split(/\s+/).filter(Boolean);
    const ftsQuery = terms.map(t => `"${t.replace(/"/g, '""')}"`).join(" OR ");

    let sql = `
      SELECT f.path, f.type, f.tags, f.title,
             substr(f.content, 1, 200) as excerpt,
             bm25(files_fts) as score
      FROM files f
      JOIN files_fts ft ON f.rowid = ft.rowid
      WHERE files_fts MATCH ?
    `;
    const params: unknown[] = [ftsQuery];

    if (type) {
      sql += " AND f.type = ?";
      params.push(type);
    }
    if (domain) {
      if (domain === "coding+personal") {
        sql += " AND (f.domain = 'coding' OR f.domain = 'personal')";
      } else if (domain === "both") {
        sql += " AND (f.domain = ? OR f.domain = '')";
        params.push(domain);
      } else if (domain === "coding+both") {
        sql += " AND (f.domain = 'coding' OR f.domain = 'both' OR f.domain = '')";
      } else {
        sql += " AND f.domain = ?";
        params.push(domain);
      }
    }

    sql += " ORDER BY score LIMIT ?";
    params.push(limit);

    try {
      const rows = this.db.prepare(sql).all(...params) as Array<Record<string, unknown>>;
      return rows.map(r => ({
        file: r.path as string,
        type: r.type as string,
        tags: (r.tags as string) ? (r.tags as string).split(",").filter(Boolean) : [],
        title: r.title as string,
        excerpt: r.excerpt as string,
        score: r.score as number,
      }));
    } catch {
      return this._searchFallback(query, limit, type, domain);
    }
  }

  private _searchFallback(query: string, limit: number, type?: string, domain?: string): SearchResult[] {
    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    let sql = "SELECT * FROM files";
    const conditions: string[] = [];
    const params: unknown[] = [];

    if (type) {
      conditions.push("type = ?");
      params.push(type);
    }
    if (domain) {
      if (domain === "coding+personal") {
        conditions.push("(domain = 'coding' OR domain = 'personal')");
      } else if (domain === "coding+both") {
        conditions.push("(domain = 'coding' OR domain = 'both' OR domain = '')");
      } else if (domain === "both") {
        conditions.push("(domain = ? OR domain = '')");
        params.push(domain);
      } else {
        conditions.push("domain = ?");
        params.push(domain);
      }
    }

    if (conditions.length > 0) {
      sql += " WHERE " + conditions.join(" AND ");
    }

    const files = this.db.prepare(sql).all(...params) as IndexedFile[];

    return files
      .map(f => {
        const text = `${f.path} ${f.title} ${f.content} ${f.tags}`.toLowerCase();
        const matches = terms.filter(t => text.includes(t)).length;
        return { file: f, score: matches / terms.length };
      })
      .filter(({ score }) => score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, limit)
      .map(({ file: f, score }) => ({
        file: f.path,
        type: f.type,
        tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
        title: f.title,
        excerpt: f.content.slice(0, 200),
        score,
      }));
  }

  // ─── Stats ─────────────────────────────────────────────────────────

  stats(): { files: number; types: Record<string, number> } {
    const count = this.db.prepare("SELECT COUNT(*) as c FROM files").get() as { c: number };
    const typeRows = this.db.prepare(
      "SELECT type, COUNT(*) as c FROM files GROUP BY type"
    ).all() as Array<{ type: string; c: number }>;

    const types: Record<string, number> = {};
    for (const row of typeRows) {
      types[row.type] = row.c;
    }

    return { files: count.c, types };
  }

  // ─── Lifecycle ─────────────────────────────────────────────────────

  close(): void {
    this.db.close();
  }
}

#!/usr/bin/env tsx
// sync-index.ts — Rebuild/update the SQLite index from markdown files
// Usage: tsx scripts/sync-index.ts [--rebuild]

import { join } from "node:path";
import { BrainStore } from "./store.js";
import { scanBrainFiles, extractTitle, tagsToString, dateToString } from "./markdown.js";

const ROOT_DIR = join(import.meta.dirname, "..");
const DB_PATH = join(ROOT_DIR, "index", "memory.db");
const rebuild = process.argv.includes("--rebuild");

async function main(): Promise<void> {
  const store = new BrainStore(DB_PATH);

  console.log(rebuild ? "Rebuilding index..." : "Updating index...");

  // Scan markdown files
  const files = await scanBrainFiles();
  console.log(`Found ${files.length} markdown files in brain/`);

  // If rebuild, we could drop all — but UPSERT handles updates, and we
  // handle deletions below. For a true rebuild, delete everything first.
  if (rebuild) {
    const existing = store.listFiles();
    for (const f of existing) {
      store.deleteFile(f.path);
    }
    console.log(`Cleared ${existing.length} old entries`);
  }

  // Upsert each file
  let updated = 0;
  let skipped = 0;

  for (const file of files) {
    const existing = store.getFile(file.path);
    if (!rebuild && existing && existing.checksum === file.checksum) {
      skipped++;
      continue;
    }

    const title = extractTitle(file.content, file.frontmatter);
    const domain = file.frontmatter.domain || "";
    store.upsertFile({
      path: file.path,
      checksum: file.checksum,
      type: file.frontmatter.type || "unknown",
      tags: tagsToString(file.frontmatter.tags || []),
      title,
      content: file.content,
      updated: dateToString(file.frontmatter.updated) || dateToString(file.frontmatter.date) || "",
      domain,
      indexed_at: new Date().toISOString(),
    });
    updated++;
  }

  // Remove stale entries (files that no longer exist)
  if (!rebuild) {
    const indexedPaths = new Set(files.map(f => f.path));
    const allIndexed = store.listFiles();
    let removed = 0;
    for (const entry of allIndexed) {
      if (!indexedPaths.has(entry.path)) {
        store.deleteFile(entry.path);
        removed++;
      }
    }
    if (removed > 0) console.log(`Removed ${removed} stale entries`);
  }

  const stats = store.stats();
  console.log(`Done. ${updated} updated, ${skipped} skipped.`);
  console.log(`Index: ${stats.files} files`);
  for (const [type, count] of Object.entries(stats.types)) {
    console.log(`  ${type}: ${count}`);
  }

  store.close();
}

main().catch(err => {
  console.error("sync-index failed:", err);
  process.exit(1);
});

// Shared types for the third-brain system

export type BrainFileType = "daily" | "person" | "projects" | "patterns" | "sessions" | "self";

export type DomainType = "coding" | "personal" | "both";

export interface BrainFileFrontmatter {
  type: BrainFileType;
  tags: string[];
  title?: string;
  domain?: DomainType;
  updated?: string;
  date?: string;
  name?: string;
  status?: string;
  confidence?: string;
}

export interface BrainFile {
  /** Path relative to brain/ directory */
  path: string;
  /** Full absolute path */
  absolutePath: string;
  /** Parsed frontmatter */
  frontmatter: BrainFileFrontmatter;
  /** Markdown content (below frontmatter) */
  content: string;
  /** Raw file content */
  raw: string;
  /** SHA-256 checksum for change detection */
  checksum: string;
}

export interface IndexedFile {
  path: string;
  checksum: string;
  type: string;
  tags: string;
  title: string;
  content: string;
  updated: string;
  indexed_at: string;
  domain?: string;
}

export interface SearchResult {
  file: string;
  type: string;
  tags: string[];
  title: string;
  excerpt: string;
  score: number;
}

export interface MemoryInput {
  type: BrainFileType;
  file: string;
  section?: string;
  content: string;
  tags: string[];
}

export interface DedupReport {
  duplicates: Array<{
    type: "exact" | "near" | "stale" | "conflict";
    files: string[];
    excerpt: string;
    suggestion: string;
  }>;
  stats: {
    totalEntries: number;
    duplicateGroups: number;
    staleEntries: number;
    conflicts: number;
  };
}

