// Shared types for the third-brain system

export type BrainFileType = "daily" | "person" | "projects" | "patterns" | "sessions" | "self";

export type DomainType = "coding" | "personal" | "both";

export interface BrainFileFrontmatter {
  type: BrainFileType;
  tags: string[];
  title?: string;
  domain?: DomainType;
  updated?: string;
  date?: string;
  name?: string;
  status?: string;
  confidence?: string;
}

export interface BrainFile {
  /** Path relative to brain/ directory */
  path: string;
  /** Full absolute path */
  absolutePath: string;
  /** Parsed frontmatter */
  frontmatter: BrainFileFrontmatter;
  /** Markdown content (below frontmatter) */
  content: string;
  /** Raw file content */
  raw: string;
  /** SHA-256 checksum for change detection */
  checksum: string;
}

export interface IndexedFile {
  path: string;
  checksum: string;
  type: string;
  tags: string;
  title: string;
  content: string;
  updated: string;
  indexed_at: string;
  domain?: string;
}

export interface SearchResult {
  file: string;
  type: string;
  tags: string[];
  title: string;
  excerpt: string;
  score: number;
}

export interface MemoryInput {
  type: BrainFileType;
  file: string;
  section?: string;
  content: string;
  tags: string[];
}

export interface DedupReport {
  duplicates: Array<{
    type: "exact" | "near" | "stale" | "conflict";
    files: string[];
    excerpt: string;
    suggestion: string;
  }>;
  stats: {
    totalEntries: number;
    duplicateGroups: number;
    staleEntries: number;
    conflicts: number;
  };
}

