// git.ts — Git helpers for the third-brain
// Shared between Pi extension and Claude Code hooks

import { execFileSync } from "node:child_process";

/**
 * Stage a brain file and commit if there are changes.
 *
 * @param rootDir  Git repo root (e.g. third-brain dir)
 * @param fileRel  Path relative to brain/ directory
 * @param message  Commit message (type is always `feat(brain):`)
 * @returns true if committed, false if nothing to stage
 */
export function commitFile(rootDir: string, fileRel: string, message: string): boolean {
  try {
    execFileSync("git", ["add", `brain/${fileRel}`], { cwd: rootDir, stdio: "pipe" });
    execFileSync("git", ["diff", "--cached", "--quiet"], { cwd: rootDir, stdio: "pipe" });
    // exit 0 = nothing staged — no-op
    return false;
  } catch {
    // exit non-zero = changes staged — commit
    const desc = message.slice(0, 60).replace(/\s+/g, " ").trim();
    const msg = `feat(brain): ${desc}`;
    execFileSync("git", ["commit", "-m", msg], { cwd: rootDir, stdio: "pipe" });
    console.log(`Committed: ${msg}`);
    return true;
  }
}

content.thinking:
I need to replace the try/catch flow control with a proper error code check. `execFileSync` throws on non-zero exit codes by default, but I can use `{ throws: false }` or check the status. Actually, in Node.js's `execFileSync`, there's no `throws` option. But I can use a different approach - use `spawnSync` which returns an object with `status`:

```typescript
import { spawnSync } from "node:child_process";
```

Or I can keep using `execFileSync` but structure it properly. One approach:

```typescript
export function commitFile(rootDir: string, fileRel: string, message: string): boolean {
  // Stage the file
  execFileSync("git", ["add", `brain/${fileRel}`], { cwd: rootDir, stdio: "pipe" });

  // Check if there are changes staged
  try {
    execFileSync("git", ["diff", "--cached", "--quiet"], { cwd: rootDir, stdio: "pipe" });
    // exit 0 = nothing staged — no-op
    return false;
  } catch {
    // exit non-zero = changes staged
    const desc = message.slice(0, 60).replace(/\s+/g, " ").trim();
    const msg = `feat(brain): ${desc}`;
    execFileSync("git", ["commit", "-m", msg], { cwd: rootDir, stdio: "pipe" });
    console.log(`Committed: ${msg}`);
    return true;
  }
}
```

Actually, the issue is that the try/catch around `git diff --cached --quiet` also catches errors from the `git add` above it. And if `git add` fails (unlikely but possible), it would incorrectly try to commit.

A better approach: separate the operations, and catch only the `git diff` call. Let me rewrite:

```typescript
export function commitFile(rootDir: string, fileRel: string, message: string): boolean {
  // Stage the file
  execFileSync("git", ["add", `brain/${fileRel}`], { cwd: rootDir, stdio: "pipe" });

  // Check if there are changes staged
  let hasChanges = false;
  try {
    execFileSync("git", ["diff", "--cached", "--quiet"], { cwd: rootDir, stdio: "pipe" });
  } catch {
    // Non-zero exit = changes staged
    hasChanges = true;
  }

  if (!hasChanges) return false;

  // Commit
  const desc = message.slice(0, 60).replace(/\s+/g, " ").trim();
  const msg = `feat(brain): ${desc}`;
  execFileSync("git", ["commit", "-m", msg], { cwd: rootDir, stdio: "pipe" });
  console.log(`Committed: ${msg}`);
  return true;
}
```

This is cleaner — the `git add` is outside the try block, so if it fails, it'll throw naturally. The `git diff --cached --quiet` is the only thing in the try/catch, and the catch only means "non-zero exit from git diff" (which means changes are staged).

